const results = [];

for (const item of $input.all()) {
  const fullName = item.json.fields?.["Full Name"] || item.json.Name || '';

  // Limpiar y extraer primer nombre
  let firstName = fullName
    // Reemplazar separadores comunes por espacio
    .replace(/[|._\-]/g, ' ')
    // Eliminar caracteres especiales excepto letras y espacios
    .replace(/[^a-zA-ZáéíóúñÁÉÍÓÚÑ\s]/g, '')
    // Eliminar espacios múltiples
    .replace(/\s+/g, ' ')
    .trim()
    // Tomar primera palabra
    .split(' ')[0];

  // Convertir a Title Case (Primera letra mayúscula, resto minúscula)
  firstName = firstName.charAt(0).toUpperCase() + firstName.slice(1).toLowerCase();

  results.push({
    json: {
      ...item.json,
      firstName: firstName
    }
  });
}

return results;
